## All Files in src/ Directory

### src/validate.js
```javascript
'use strict';

function validateName(name) {
  const trimmed = String(name).trim();
  if (!trimmed) {
    throw new Error('EMPTY_NAME: name required');
  }
  return trimmed;
}

module.exports = { validateName };
```

### src/parse.js
```javascript
'use strict';

function parseIntStrict(text) {
  if (!/^-?\d+$/.test(String(text))) {
    throw new Error('BAD_INT: not an integer');
  }
  return parseInt(text, 10);
}

module.exports = { parseIntStrict };
```

### src/money.js
```javascript
'use strict';

function toCents(amount) {
  if (amount < 0) {
    throw new Error('NEG_AMOUNT: amount below zero');
  }
  return Math.round(amount * 100);
}

module.exports = { toCents };
```

### src/range.js
```javascript
'use strict';

function clamp(value, min, max) {
  if (min > max) {
    throw new Error('BAD_RANGE: min above max');
  }
  return Math.min(Math.max(value, min), max);
}

module.exports = { clamp };
```

### src/store.js
```javascript
'use strict';

const DATA = new Map();

function set(key, value) {
  DATA.set(key, value);
}

function get(key) {
  if (!DATA.has(key)) {
    throw new Error('MISSING_KEY: no such key');
  }
  return DATA.get(key);
}

module.exports = { set, get };
```

### src/auth.js
```javascript
'use strict';

function checkToken(token) {
  if (!/^tk_[a-z0-9]+$/.test(String(token))) {
    throw new Error('BAD_TOKEN: token malformed');
  }
  return true;
}

module.exports = { checkToken };
```

### src/format.js
```javascript
'use strict';

function padLeft(text, width) {
  if (!Number.isInteger(width) || width <= 0) {
    throw new Error('BAD_WIDTH: width must be positive');
  }
  return String(text).padStart(width, ' ');
}

module.exports = { padLeft };
```

### src/calc.js
```javascript
'use strict';

function divide(a, b) {
  if (b === 0) {
    throw new Error('DIV_ZERO: division by zero');
  }
  return a / b;
}

module.exports = { divide };
```

### src/dates.js
```javascript
'use strict';

function parseIso(text) {
  if (!/^\d{4}-\d{2}-\d{2}$/.test(String(text))) {
    throw new Error('BAD_DATE: not an ISO date');
  }
  const [y, m, d] = text.split('-').map(Number);
  return new Date(Date.UTC(y, m - 1, d));
}

module.exports = { parseIso };
```

### src/index.js
```javascript
'use strict';

module.exports = {
  ...require('./validate.js'),
