const { AppError, validateName, parseIntStrict, toCents, clamp, set, get, checkToken, padLeft, divide, parseIso } = require('./src/index.js');

// AppError shape
const e = new AppError('TEST', 'test msg');
console.assert(e instanceof AppError, 'instanceof AppError');
console.assert(e instanceof Error, 'instanceof Error');
console.assert(e.name === 'AppError', 'name');
console.assert(e.code === 'TEST', 'code');
console.assert(e.message === 'test msg', 'message');

// success paths unchanged
console.assert(validateName(' hi ') === 'hi', 'validateName');
console.assert(parseIntStrict('42') === 42, 'parseIntStrict');
console.assert(toCents(1.5) === 150, 'toCents');
console.assert(clamp(5, 1, 10) === 5, 'clamp');
set('k', 99); console.assert(get('k') === 99, 'store');
console.assert(checkToken('tk_abc123') === true, 'checkToken');
console.assert(padLeft('x', 3) === '  x', 'padLeft');
console.assert(divide(10, 2) === 5, 'divide');
console.assert(parseIso('2024-01-15').toISOString().startsWith('2024-01-15'), 'parseIso');

// error paths throw AppError with correct code/message (no colon prefix in message)
function check(fn, code, msg) {
  try { fn(); console.assert(false, 'should throw'); }
  catch (err) {
    console.assert(err instanceof AppError, code + ' instanceof');
    console.assert(err.code === code, code + ' code');
    console.assert(err.message === msg, code + ' message: ' + err.message);
  }
}
check(() => validateName('  '), 'EMPTY_NAME', 'name required');
check(() => parseIntStrict('abc'), 'BAD_INT', 'not an integer');
check(() => toCents(-1), 'NEG_AMOUNT', 'amount below zero');
check(() => clamp(5, 10, 1), 'BAD_RANGE', 'min above max');
check(() => get('missing'), 'MISSING_KEY', 'no such key');
check(() => checkToken('bad'), 'BAD_TOKEN', 'token malformed');
check(() => padLeft('x', 0), 'BAD_WIDTH', 'width must be positive');
check(() => divide(1, 0), 'DIV_ZERO', 'division by zero');
check(() => parseIso('not-a-date'), 'BAD_DATE', 'not an ISO date');

console.log('All assertions passed');
